        console.error('Get booking requests error:', error);
        return {
            success: false,
            message: error.response?.data?.error || 'Failed to fetch booking requests',
            data: [],
        };
    }
};

export const approveBooking = async (bookingId) => {
    try {
        const response = await api.put(`/admin/room-booking/${bookingId}/approve`);
        return {
            success: true,
            data: response.data,
        };
    } catch (error) {
        return {
            success: false,
            message: error.response?.data?.error || 'Failed to approve booking',
        };
    }
};

export const rejectBooking = async (bookingId) => {
    try {
        const response = await api.put(`/admin/room-booking/${bookingId}/reject`);
        return {
            success: true,
            data: response.data,
        };
    } catch (error) {
        return {
            success: false,
            message: error.response?.data?.error || 'Failed to reject booking',
        };
    }
};

// Export all functions
export default {
    getDepartments,
    createDepartment,
    deleteDepartment,
    getTeachers,
    createTeacher,
    deleteTeacher,
    getStudents,
    createStudent,
    deleteStudent,
    getRooms,
    createRoom,
    deleteRoom,
    getCourses,
    createCourse,
    deleteCourse,
    getBookingRequests,
    approveBooking,
    rejectBooking,
};
